/* ===== FULL CHAT COMPAT PATCH START ===== */
(function () {
    'use strict';
    function log(){ try{ console.log('[CHAT-COMPAT]', ...arguments); }catch(_){} }
    function findApp(){ return window.app || window.App || globalThis.app || globalThis.App || null; }
    function ensureChatConnected(app){
        try{
            if(!app) return;
            if(app.player && !app.player.chat){
                if(typeof app.initChat === 'function'){ app.initChat(); log('initChat() called'); }
                else if(typeof app.reconnectChat === 'function'){ app.reconnectChat(); log('reconnectChat() called'); }
            }else if(app.player && app.player.chat && typeof app.player.chat.connect === 'function' && !app.player.chat.isConnected){
                try{ app.player.chat.connect(); log('player.chat.connect() called'); }catch(_){}
            }
        }catch(e){ log('ensureChatConnected error', e); }
    }
    function getCurrentConnection(app){
        try{
            if(app?.dualConnectionHandler?.current) return app.dualConnectionHandler.current;
            if(Array.isArray(app?.dualConnectionHandler?.list) && app.dualConnectionHandler.list.length) return app.dualConnectionHandler.list[0];
        }catch(_){}
        return null;
    }
    function getNick(app,current){
        try{
            if(current?.type === 'Primary' && app?.player?.nickname1) return app.player.nickname1;
            if(current?.type === 'Secondary' && app?.player?.nickname2) return app.player.nickname2;
            if(app?.unitManager?.activeUnit?.profile?.nick) return app.unitManager.activeUnit.profile.nick;
            if(app?.player?.nickname1) return app.player.nickname1;
            if(app?.profile?.nick) return app.profile.nick;
        }catch(_){}
        return 'noname';
    }
    function processText(app,text){
        try{ if(app?.chatBox?.processShortcuts) return app.chatBox.processShortcuts(text); }catch(_){}
        return text;
    }
    function tryOldConnectionSend(app,text){
        try{
            const current = getCurrentConnection(app);
            const conn = current?.chatTab?.connection;
            const chatId = current?.chatTab?.chatId || 0;
            if(conn && typeof conn.sendChatMessage === 'function'){
                conn.sendChatMessage({ type:'msg', userID:0, playerID:chatId, targetID:0, nick:getNick(app,current), text:processText(app,text) });
                log('sent via current.chatTab.connection.sendChatMessage');
                return true;
            }
        }catch(e){ log('oldConnectionSend error', e); }
        return false;
    }
    function tryPlayerChatSend(app,text){
        try{
            const playerChat = app?.player?.chat;
            const current = getCurrentConnection(app);
            const chatId = current?.chatTab?.chatId || 0;
            if(playerChat && typeof playerChat.sendChatMessage === 'function'){
                playerChat.sendChatMessage({ type:'msg', userID:0, playerID:chatId, targetID:0, nick:getNick(app,current), text:processText(app,text) });
                log('sent via app.player.chat.sendChatMessage');
                return true;
            }
        }catch(e){ log('playerChatSend error', e); }
        return false;
    }
    function tryEventBusSend(app,text){
        try{
            if(app?.chat && typeof app.chat.emit === 'function'){
                app.chat.emit('sendChatMessage', 'msg', processText(app,text));
                log('sent via app.chat.emit(sendChatMessage)');
                return true;
            }
        }catch(e){ log('eventBusSend error', e); }
        return false;
    }
    function tryChatMethodSend(app,text){
        try{
            if(app?.chat && typeof app.chat.sendChatMessage === 'function'){
                try{ app.chat.sendChatMessage('msg', processText(app,text)); log('sent via app.chat.sendChatMessage(type,text)'); return true; }catch(_){}
                try{ app.chat.sendChatMessage({ type:'msg', text:processText(app,text) }); log('sent via app.chat.sendChatMessage(object)'); return true; }catch(_){}
            }
        }catch(e){ log('chatMethodSend error', e); }
        return false;
    }
    function tryRootSocketSend(app,text){
        try{
            const rootSocket = app?.RootSocket || app?.rootSocket || app?.socket || app?.connection || null;
            const ac = window.ac || globalThis.ac;
            const current = getCurrentConnection(app);
            const playerID = current?.playerID || current?.chatTab?.chatId || app?.playerID || app?.unitManager?.activeUnit?.playerID || null;
            const connectionID = rootSocket?.connectionID || app?.connectionID || 0;
            const isOpen = (typeof rootSocket?.isSocketOpen === 'function' && rootSocket.isSocketOpen()) || (rootSocket?.socket && rootSocket.socket.readyState === 1) || rootSocket?.established === true;
            if(!rootSocket || !isOpen || !playerID || !ac?.create?.message) return false;
            const packet = ac.create.message({ type:'msg', userID:connectionID, playerID:playerID, targetID:0, nick:getNick(app,current), text:processText(app,text) });
            if(typeof rootSocket.sendBuffer === 'function'){ rootSocket.sendBuffer(packet); log('sent via RootSocket.sendBuffer'); return true; }
            if(typeof rootSocket.send === 'function'){ rootSocket.send(packet); log('sent via RootSocket.send'); return true; }
        }catch(e){ log('rootSocketSend error', e); }
        return false;
    }
    function sendChatCompat(text){
        const app = findApp();
        if(!app){ log('app not found'); return false; }
        ensureChatConnected(app);
        return tryOldConnectionSend(app,text) || tryPlayerChatSend(app,text) || tryEventBusSend(app,text) || tryChatMethodSend(app,text) || tryRootSocketSend(app,text);
    }
    function bindInput(){
        const app = findApp();
        const input = document.getElementById('chat-input') || document.querySelector('#chat-input') || app?.chatBox?.inputField || document.querySelector('input[name="chatmessage"]');
        if(!input || input.dataset.chatCompatBound === '1') return;
        input.dataset.chatCompatBound = '1';
        input.addEventListener('keydown', function(e){
            if(e.key !== 'Enter') return;
            const text = String(input.value || '').trim();
            if(!text) return;
            const ok = sendChatCompat(text);
            if(ok){
                e.preventDefault(); e.stopPropagation();
                if(typeof e.stopImmediatePropagation === 'function') e.stopImmediatePropagation();
                input.value = '';
            }
        }, true);
        log('chat input hooked');
    }
    function patchChatBox(){
        const app = findApp();
        const chatBox = app?.chatBox;
        if(!chatBox || chatBox.__chatCompatPatched) return;
        chatBox.__chatCompatPatched = true;
        const originalSend = typeof chatBox.sendMessage === 'function' ? chatBox.sendMessage.bind(chatBox) : null;
        chatBox.sendMessage = function(text){
            if(sendChatCompat(text)) return true;
            if(originalSend) return originalSend(text);
            return false;
        };
        log('chatBox.sendMessage patched');
    }
    function heartbeat(){
        bindInput();
        patchChatBox();
        const app = findApp();
        if(app) ensureChatConnected(app);
    }
    if(document.readyState === 'loading') document.addEventListener('DOMContentLoaded', heartbeat); else heartbeat();
    setInterval(heartbeat, 1500);
    window.sendChatCompat = sendChatCompat;
})();
/* ===== FULL CHAT COMPAT PATCH END ===== */
